#include <cuda_runtime.h>
#include <cstdint>

// Tile size for shared memory blocking
constexpr int TILE_M = 128;
constexpr int TILE_N = 128;
constexpr int TILE_K = 16;

// Warp tile size for computation
constexpr int WARP_M = 32;
constexpr int WARP_N = 64;

// Thread block size
constexpr int BLOCK_SIZE = 256;

__global__ void matmul_bias_kernel(
    const half* __restrict__ A,
    const half* __restrict__ B,
    const float* __restrict__ bias,
    float* __restrict__ output,
    int M, int K, int N
) {
    // Shared memory for tiles
    __shared__ half smem_A[TILE_M * TILE_K];
    __shared__ half smem_B[TILE_K * TILE_N];

    // Thread and block indices
    const int tid = threadIdx.x;
    const int block_row = blockIdx.y;
    const int block_col = blockIdx.x;

    // Global output position for this block
    const int row_base = block_row * TILE_M;
    const int col_base = block_col * TILE_N;

    // Number of threads per tile dimension for loading
    const int num_threads = BLOCK_SIZE;
    const int A_tile_size = TILE_M * TILE_K;
    const int B_tile_size = TILE_K * TILE_N;

    // Accumulator registers (each thread computes multiple outputs)
    const int threads_per_row_A = TILE_K;
    const int threads_per_row_B = TILE_N;

    // Each thread handles multiple elements in output tile
    const int thread_row = tid / (TILE_N / 8);
    const int thread_col = (tid % (TILE_N / 8)) * 8;

    float acc[8][8] = {0.0f};

    // Loop over K dimension in tiles
    const int num_k_tiles = (K + TILE_K - 1) / TILE_K;

    for (int k_tile = 0; k_tile < num_k_tiles; ++k_tile) {
        const int k_base = k_tile * TILE_K;

        // Load tile of A into shared memory (cooperative loading)
        for (int i = tid; i < A_tile_size; i += num_threads) {
            int local_row = i / TILE_K;
            int local_col = i % TILE_K;
            int global_row = row_base + local_row;
            int global_col = k_base + local_col;

            if (global_row < M && global_col < K) {
                smem_A[local_row * TILE_K + local_col] = A[global_row * K + global_col];
            } else {
                smem_A[local_row * TILE_K + local_col] = __float2half(0.0f);
            }
        }

        // Load tile of B into shared memory (cooperative loading)
        for (int i = tid; i < B_tile_size; i += num_threads) {
            int local_row = i / TILE_N;
            int local_col = i % TILE_N;
            int global_row = k_base + local_row;
            int global_col = col_base + local_col;

            if (global_row < K && global_col < N) {
                smem_B[local_row * TILE_N + local_col] = B[global_row * N + global_col];
            } else {
                smem_B[local_row * TILE_N + local_col] = __float2half(0.0f);
            }
        }

        __syncthreads();

        // Compute partial dot products
        #pragma unroll
        for (int k = 0; k < TILE_K; ++k) {
            // Load A elements for this thread's rows
            half a_vals[8];
            #pragma unroll
            for (int i = 0; i < 8; ++i) {
                int row = thread_row * 8 + i;
                if (row < TILE_M) {
                    a_vals[i] = smem_A[row * TILE_K + k];
                } else {
                    a_vals[i] = __float2half(0.0f);
                }
            }

            // Load B elements for this thread's columns
            half b_vals[8];
            #pragma unroll
            for (int j = 0; j < 8; ++j) {
                int col = thread_col + j;
                if (col < TILE_N) {
                    b_vals[j] = smem_B[k * TILE_N + col];
                } else {
                    b_vals[j] = __float2half(0.0f);
                }
            }

            // Outer product accumulation
            #pragma unroll
            for (int i = 0; i < 8; ++i) {
                #pragma unroll
                for (int j = 0; j < 8; ++j) {
                    acc[i][j] += __half2float(a_vals[i]) * __half2float(b_vals[j]);
                }
            }
        }

        __syncthreads();
    }

    // Write results to global memory with bias addition
    #pragma unroll
    for (int i = 0; i < 8; ++i) {
        int global_row = row_base + thread_row * 8 + i;
        if (global_row >= M) continue;

        #pragma unroll
        for (int j = 0; j < 8; ++j) {
            int global_col = col_base + thread_col + j;
            if (global_col < N) {
                float bias_val = bias[global_col];
                output[global_row * N + global_col] = acc[i][j] + bias_val;
            }
        }
    }
}

extern "C" void cuda_kernel(
    const half* A,
    const half* B,
    const float* bias,
    float* output,
    int M, int K, int N
) {
    // Grid and block dimensions
    dim3 block(BLOCK_SIZE);
    dim3 grid(
        (N + TILE_N - 1) / TILE_N,
        (M + TILE_M - 1) / TILE_M
    );

    matmul_bias_kernel<<<grid, block>>>(A, B, bias, output, M, K, N);
}
