{"content":"#include <cuda_fp16.h>
#include <cuda_runtime.h>
#include <mma.h>

using namespace nvcuda;

// Tensor Core configuration for A100
constexpr int WMMA_M = 16;
constexpr int WMMA_N = 16;
constexpr int WMMA_K = 16;

// Block tile configuration
constexpr int BLOCK_M = 128;
constexpr int BLOCK_N = 128;
constexpr int BLOCK_K = 32;

// Warp configuration
constexpr int WARPS_M = 4; // BLOCK_M / (WMMA_M * warps_per_col)
constexpr int WARPS_N = 2; // BLOCK_N / (WMMA_N * warps_per_row)
constexpr int BLOCK_SIZE = 256; // WARPS_M * WARPS_N * 32

__global__ void matmul_bias_kernel_tc(
    const half* __restrict__ A,
    const half* __restrict__ B,
    const float* __restrict__ bias,
    float* __restrict__ output,
    int M, int K, int N
) {
    // Warp and lane identification
    const int warp_id = threadIdx.x / 32;
    const int lane_id = threadIdx.x % 32;
    const int warp_row = warp_id / WARPS_N;
    const int warp_col = warp_id % WARPS_N;

    // Block tile position
    const int block_row = blockIdx.y * BLOCK_M;
    const int block_col = blockIdx.x * BLOCK_N;

    // Shared memory for tiles
    __shared__ half smem_A[BLOCK_M * BLOCK_K];
    __shared__ half smem_B[BLOCK_K * BLOCK_N];

    // Tensor Core fragment accumulators
    wmma::fragment<wmma::accumulator, WMMA_M, WMMA_N, WMMA_K, float> acc[4][4];

    // Initialize accumulators
    #pragma unroll
    for (int i = 0; i < 4; ++i) {
        #pragma unroll
        for (int j = 0; j < 4; ++j) {
            wmma::fill_fragment(acc[i][j], 0.0f);
        }
    }

    // Main K loop
    const int num_k_tiles = (K + BLOCK_K - 1) / BLOCK_K;

    for (int k_tile = 0; k_tile < num_k_tiles; ++k_tile) {
        const int k_base = k_tile * BLOCK_K;

        // Cooperative loading of A tile (M x K)
        const int A_tile_elements = BLOCK_M * BLOCK_K;
        for (int idx = threadIdx.x; idx < A_tile_elements; idx += BLOCK_SIZE) {
            int row = idx / BLOCK_K;
            int col = idx % BLOCK_K;
            int global_row = block_row + row;
            int global_col = k_base + col;

            if (global_row < M && global_col < K) {
                smem_A[row * BLOCK_K + col] = A[global_row * K + global_col];
            } else {
                smem_A[row * BLOCK_K + col] = __float2half(0.0f);
            }
        }

        // Cooperative loading of B tile (K x N)
        const int B_tile_elements = BLOCK_K * BLOCK_N;
        for (int idx = threadIdx.x; idx < B_tile_elements; idx += BLOCK_SIZE) {
            int row = idx / BLOCK_N;
            int col = idx % BLOCK_N;
            int global_row = k_base + row;
            int global_col = block_col + col;

            if (global_row < K && global_col < N) {
                smem_B[row * BLOCK_N + col] = B[global_row * N + global_col];
            } else {
                smem_B[row * BLOCK_N + col] = __float2half(0.0f);
            }
        }

        __syncthreads();

        // Tensor Core computation
        #pragma unroll
        for (int k = 0; k < BLOCK_K; k += WMMA_K) {
            // Each warp computes 4x4 tiles of 16x16 output elements
            #pragma unroll
            for (int i = 0; i < 4; ++i) {
                #pragma unroll
                for (int j = 0; j < 4; ++j) {
                    int row_offset = warp_row * 64 + i * WMMA_M;
                    int col_offset = warp_col * 64 + j * WMMA_N;

                    wmma::fragment<wmma::matrix_a, WMMA_M, WMMA_N, WMMA_K, half, wmma::row_major> a_frag;
                    wmma::fragment<wmma::matrix_b, WMMA_M, WMMA_N, WMMA_K, half, wmma::row_major> b_frag;

                    wmma::load_matrix_sync(a_frag, &smem_A[row_offset * BLOCK_K + k], BLOCK_K);
                    wmma::load_matrix_sync(b_frag, &smem_B[k * BLOCK_N + col_offset], BLOCK_N);

                    wmma::mma_sync(acc[i][j], a_frag, b_frag, acc[i][j]);
                }
            }
        }

        __syncthreads();
    }

    // Store results with bias
    #pragma unroll
    for (int i = 0; i < 4; ++i) {
        #pragma unroll
        for (int j = 0; j < 4; ++j) {
            int row_offset = block_row + warp_row * 64 + i * WMMA_M;
            int col_offset = block_col + warp_col * 64 + j * WMMA_N;

            if (row_offset < M && col_offset < N) {
                // Load fragment to registers
                float result[8];
                wmma::store_matrix_sync(result, acc[i][j], 8, wmma::mem_row_major);

                // Add bias and write to global memory
                for (int elem = 0; elem < 8; ++elem) {
                    int lane_row = elem / 2;
                    int lane_col = (elem % 2) * 8 + (lane_id % 4) * 2 + (lane_id / 16);
                    int global_row = row_offset + lane_row + (lane_id / 4) % 4;
                    int global_col = col_offset + lane_col;

                    if (global_row < M && global_col < N) {
                        output[global_row * N + global_col] = result[elem] + bias[global_col];
                    }
                }
            }
        }
    }
}

// Fallback kernel for non-Tensor Core path (smaller matrices or unsupported configs)
__global__ void matmul_bias_kernel_fallback(
    const half* __restrict__ A,
    const half* __restrict__ B,
    const float* __restrict__ bias,
    float* __restrict__ output,
    int M, int K, int N
) {
    const int TILE_M = 128;
    const int TILE_N = 128;
    const int TILE_K = 16;
    const int BLOCK_THREADS = 256;

    __shared__ half smem_A[TILE_M * TILE_K];
    __shared__ half smem_B[TILE_K * TILE_N];

    const int tid = threadIdx.x;
    const int block_row = blockIdx.y;
    const int block_col = blockIdx.x;

    const int row_base = block_row * TILE_M;
    const int col_base = block_col * TILE_N;

    // Each thread computes 8x8 elements
    const int thread_row = tid / 16;
    const int thread_col = (tid % 16) * 8;

    float acc[8][8];
    #pragma unroll
    for (int i = 0; i < 8; ++i) {
        #pragma unroll
        for (int j = 0; j < 8; ++j) {
            acc[i][j] = 0.0f;
        }
    }

    const int num_k_tiles = (K + TILE_K - 1) / TILE_K;

    for (int k_tile = 0; k_tile < num_k_tiles; ++k_tile) {
        const int k_base = k_tile * TILE_K;

        // Load A tile
        for (int i = tid; i < TILE_M * TILE_K; i += BLOCK_THREADS) {
            int local_row = i / TILE_K;
            int local_col = i % TILE_K;
            int global_row = row_base + local_row;
            int global_col = k_base + local_col;

            if (global_row < M && global_col < K) {
                smem_A[local_row * TILE_K + local_col] = A[global_row * K + global_col];
            } else {
                smem_A[local_row * TILE_K + local_col] = __float2half(0.0f);
            }
        }

        // Load B tile
        for (int i = tid; i < TILE_K * TILE_N; i += BLOCK_THREADS) {
            int local_row = i / TILE_N;
            int local_col = i % TILE_N;
            int global_row = k_base + local_row;
            int global_col = col_base + local_col;

            if (global_row < K && global_col < N) {
                smem_B[local_row * TILE_N + local_col] = B[global_row * N + global_col];
            } else {
                smem_B[local_row * TILE_N + local_col] = __float2half(0.0f);
            }
        }

        __syncthreads();

        // Compute
        #pragma unroll
        for (int k = 0; k < TILE_K; ++k) {
            half a_vals[8];
            half b_vals[8];

            #pragma unroll
            for (int i = 0; i < 8; ++i) {
                int row = thread_row * 8 + i;
                a_vals[i] = (row < TILE_M) ? smem_A[row * TILE_K + k] : __float2half(0.0f);
            }

            #pragma unroll
            for (int j = 0; j < 8; ++j) {
                int col = thread_col + j;
                b_vals[j] = (col < TILE_N) ? smem_B[k * TILE_N + col] : __float2half(0.0f);
            }

            #pragma unroll
            for (int i = 0; i < 8; ++i) {
                #pragma unroll
                for (int j = 0; j < 8; ++j) {
                    acc[i][j] += __half2float(a_vals[i]) * __half2float(b_vals[j]);
                }
            }
        }

        __syncthreads();
    }

    // Write output with bias
    #pragma unroll
    for (int i = 0; i < 8; ++i) {
        int global_row = row_base + thread_row * 8 + i;
        if (global_row >= M) continue;

        #pragma unroll
        for (int j = 0; j < 8; ++j) {
            int global_col = col_base + thread_col + j;
            if (global_col < N) {
                output[global_row * N + global_col] = acc[i][j] + bias[global_col];
            }
        }
    }
}

extern "C" void cuda_kernel(
    const half* A,
    const half* B,
    const float* bias,
    float* output,
    int M, int K, int N
) {
    // Use Tensor Core kernel for larger matrices
    bool use_tensor_cores = (M >= 64 && N >= 64 && K >= 64);

    if (use_tensor_cores) {
        dim3 block(BLOCK_SIZE);
        dim3 grid(
            (N + BLOCK_N - 1) / BLOCK_N,
            (M + BLOCK_M - 1) / BLOCK_M
        );
        matmul_bias_kernel_tc<<<grid, block>>>(A, B, bias, output, M, K, N);
    } else {
        dim3 block(256);
        dim3 grid(
            (N + 127) / 128,
            (M + 127) / 128
        );
        matmul_bias_kernel_fallback<<<grid, block>>>(A, B, bias, output, M, K, N);
    }
}
