{"content":"#include <cuda_fp16.h>
#include <cuda_runtime.h>
#include <mma.h>

using namespace nvcuda;

// Tensor Core tile sizes
constexpr int WMMA_M = 16;
constexpr int WMMA_N = 16;
constexpr int WMMA_K = 16;

// Block configuration
constexpr int BLOCK_ROW_TILES = 4;  // 4 * 16 = 64 rows per block
constexpr int BLOCK_COL_TILES = 4;  // 4 * 16 = 64 cols per block
constexpr int BLOCK_K_TILES = 2;    // 2 * 16 = 32 K dimension per iteration

constexpr int BLOCK_M = BLOCK_ROW_TILES * WMMA_M;  // 64
constexpr int BLOCK_N = BLOCK_COL_TILES * WMMA_N;  // 64
constexpr int BLOCK_K = BLOCK_K_TILES * WMMA_K;    // 32

constexpr int WARPS_PER_BLOCK = 4;
constexpr int THREADS_PER_BLOCK = WARPS_PER_BLOCK * 32;

__global__ void matmul_bias_kernel_tc(
    const half* __restrict__ A,
    const half* __restrict__ B,
    const float* __restrict__ bias,
    float* __restrict__ output,
    int M, int K, int N
) {
    // Warp identification
    const int warp_id = threadIdx.x / 32;

    // Block tile position
    const int block_row = blockIdx.y;
    const int block_col = blockIdx.x;

    // Each warp handles one 16x16 output tile
    const int warp_row = warp_id / 2;  // 0 or 1
    const int warp_col = warp_id % 2;  // 0 or 1

    // Shared memory buffers
    __shared__ half smem_A[BLOCK_M * BLOCK_K];
    __shared__ half smem_B[BLOCK_K * BLOCK_N];

    // Accumulator fragments (each warp computes 4 tiles: 2x2 grid of 16x16)
    wmma::fragment<wmma::accumulator, WMMA_M, WMMA_N, WMMA_K, float> acc[2][2];

    #pragma unroll
    for (int i = 0; i < 2; ++i) {
        #pragma unroll
        for (int j = 0; j < 2; ++j) {
            wmma::fill_fragment(acc[i][j], 0.0f);
        }
    }

    // Main loop over K dimension
    for (int k_tile = 0; k_tile < (K + BLOCK_K - 1) / BLOCK_K; ++k_tile) {
        // Load A tile (BLOCK_M x BLOCK_K) cooperatively
        int A_tile_size = BLOCK_M * BLOCK_K;
        for (int idx = threadIdx.x; idx < A_tile_size; idx += THREADS_PER_BLOCK) {
            int row = idx / BLOCK_K;
            int col = idx % BLOCK_K;
            int global_row = block_row * BLOCK_M + row;
            int global_col = k_tile * BLOCK_K + col;

            half val = __float2half(0.0f);
            if (global_row < M && global_col < K) {
                val = A[global_row * K + global_col];
            }
            smem_A[row * BLOCK_K + col] = val;
        }

        // Load B tile (BLOCK_K x BLOCK_N) cooperatively
        int B_tile_size = BLOCK_K * BLOCK_N;
        for (int idx = threadIdx.x; idx < B_tile_size; idx += THREADS_PER_BLOCK) {
            int row = idx / BLOCK_N;
            int col = idx % BLOCK_N;
            int global_row = k_tile * BLOCK_K + row;
            int global_col = block_col * BLOCK_N + col;

            half val = __float2half(0.0f);
            if (global_row < K && global_col < N) {
                val = B[global_row * N + global_col];
            }
            smem_B[row * BLOCK_N + col] = val;
        }

        __syncthreads();

        // Perform Tensor Core matrix multiplication
        // Each warp computes 2x2 = 4 output tiles of 16x16
        #pragma unroll
        for (int k = 0; k < BLOCK_K_TILES; ++k) {
            #pragma unroll
            for (int i = 0; i < 2; ++i) {
                #pragma unroll
                for (int j = 0; j < 2; ++j) {
                    int a_row = warp_row * 32 + i * WMMA_M;
                    int a_col = k * WMMA_K;
                    int b_row = k * WMMA_K;
                    int b_col = warp_col * 32 + j * WMMA_N;

                    wmma::fragment<wmma::matrix_a, WMMA_M, WMMA_N, WMMA_K, half, wmma::row_major> a_frag;
                    wmma::fragment<wmma::matrix_b, WMMA_M, WMMA_N, WMMA_K, half, wmma::row_major> b_frag;

                    wmma::load_matrix_sync(a_frag, &smem_A[a_row * BLOCK_K + a_col], BLOCK_K);
                    wmma::load_matrix_sync(b_frag, &smem_B[b_row * BLOCK_N + b_col], BLOCK_N);
                    wmma::mma_sync(acc[i][j], a_frag, b_frag, acc[i][j]);
                }
            }
        }

        __syncthreads();
    }

    // Store results to global memory with bias
    #pragma unroll
    for (int i = 0; i < 2; ++i) {
        #pragma unroll
        for (int j = 0; j < 2; ++j) {
            int out_row = block_row * BLOCK_M + warp_row * 32 + i * WMMA_M;
            int out_col = block_col * BLOCK_N + warp_col * 32 + j * WMMA_N;

            // Bounds check
            if (out_row >= M || out_col >= N) continue;

            // Load bias values for this tile
            float bias_vals[WMMA_N];
            const int lane_id = threadIdx.x % 32;
            for (int c = 0; c < WMMA_N; ++c) {
                int global_col = out_col + c;
                bias_vals[c] = (global_col < N) ? bias[global_col] : 0.0f;
            }

            // Store fragment with bias
            // We need to add bias manually since wmma::store doesn't support it directly
            float temp[WMMA_M * WMMA_N];
            wmma::store_matrix_sync(temp, acc[i][j], WMMA_N, wmma::mem_row_major);

            // Each thread in the warp handles specific elements
            for (int t = 0; t < 8; ++t) {
                int frag_row = t / 2;
                int frag_col = (t % 2) * 8;
                int lane_offset = (lane_id / 4) * 2 + (lane_id % 4) / 2;

                int elem_row = frag_row * 2 + (lane_id % 4) / 2;
                int elem_col = frag_col + lane_id % 4 + (lane_id / 16) * 4;

                int global_row = out_row + elem_row;
                int global_col = out_col + elem_col;

                if (global_row < M && global_col < N) {
                    float val = temp[elem_row * WMMA_N + elem_col];
                    output[global_row * N + global_col] = val + bias[global_col];
                }
            }
        }
    }
}

// Fallback kernel for edge cases
__global__ void matmul_bias_kernel_fallback(
    const half* __restrict__ A,
    const half* __restrict__ B,
    const float* __restrict__ bias,
    float* __restrict__ output,
    int M, int K, int N
) {
    const int TILE_M = 128;
    const int TILE_N = 128;
    const int TILE_K = 16;

    __shared__ half smem_A[TILE_M * TILE_K];
    __shared__ half smem_B[TILE_K * TILE_N];

    const int tid = threadIdx.x;
    const int row_base = blockIdx.y * TILE_M;
    const int col_base = blockIdx.x * TILE_N;

    // Each thread handles 8x8 output elements
    const int thread_row = tid / 16;
    const int thread_col = (tid % 16) * 8;

    float acc[8][8];
    for (int i = 0; i < 8; ++i) {
        for (int j = 0; j < 8; ++j) {
            acc[i][j] = 0.0f;
        }
    }

    for (int k_tile = 0; k_tile < (K + TILE_K - 1) / TILE_K; ++k_tile) {
        int k_base = k_tile * TILE_K;

        // Load A
        for (int i = tid; i < TILE_M * TILE_K; i += blockDim.x) {
            int row = i / TILE_K;
            int col = i % TILE_K;
            int g_row = row_base + row;
            int g_col = k_base + col;
            smem_A[row * TILE_K + col] = (g_row < M && g_col < K) ? 
                A[g_row * K + g_col] : __float2half(0.0f);
        }

        // Load B
        for (int i = tid; i < TILE_K * TILE_N; i += blockDim.x) {
            int row = i / TILE_N;
            int col = i % TILE_N;
            int g_row = k_base + row;
            int g_col = col_base + col;
            smem_B[row * TILE_N + col] = (g_row < K && g_col < N) ? 
                B[g_row * N + g_col] : __float2half(0.0f);
        }

        __syncthreads();

        // Compute
        for (int k = 0; k < TILE_K; ++k) {
            for (int i = 0; i < 8; ++i) {
